import { useEffect, useMemo, useState } from "react";
import api from "../api";
import { useAuth } from "../AuthContext";

/** ===== Helpers ===== */
const PAGE_SIZE = 10;

const money = (v) => (Number(v || 0)).toLocaleString("vi-VN", { maximumFractionDigits: 0 }) + " ₫";
const parseMoney = (s) => {
    if (typeof s === "number") return s;
    const digits = String(s || "").replace(/[^\d]/g, "");
    return Number(digits || 0);
};
const toISO = (d) => {
    if (!d) return "";
    if (/^\d{4}-\d{2}-\d{2}$/.test(d)) return d;
    const m = String(d).match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
    if (m) return `${m[3]}-${m[2]}-${m[1]}`;
    const dt = new Date(d);
    return isNaN(dt) ? "" : dt.toISOString().slice(0, 10);
};
const todayStr = () => {
    const d = new Date();
    const m = String(d.getMonth() + 1).padStart(2, "0");
    const day = String(d.getDate()).padStart(2, "0");
    return `${d.getFullYear()}-${m}-${day}`;
};

const statusMap = [
    { value: "PAID", label: "Đã thu" },
    { value: "PENDING", label: "Chờ duyệt" },
    { value: "CANCELLED", label: "Hủy" },
];
const statusLabel = (s) => {
    const x = String(s || "").toUpperCase();
    if (x === "PAID") return "Đã thu";
    if (x === "PENDING") return "Chờ duyệt";
    if (x === "CANCELLED" || x === "CANCELED") return "Hủy";
    return s || "-";
};

const methodMap = [
    { value: "CASH", label: "Tiền mặt" },
    { value: "TRANSFER", label: "Chuyển khoản" },
    { value: "OTHER", label: "Khác" },
];

/** ===== Component ===== */
export default function Payments() {
    const { user } = useAuth();
    const canEdit = user?.role === "ADMIN" || user?.role === "ACCOUNTANT";
    const canDelete = user?.role === "ADMIN" || user?.role === "ACCOUNTANT";

    const [contracts, setContracts] = useState([]); // {id, code, title, customerName, totalAmount}
    const [byIdContract, setByIdContract] = useState({});
    const [rows, setRows] = useState([]);           // payments
    const [loading, setLoading] = useState(true);

    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1);

    const [filterContractId, setFilterContractId] = useState("");
    const [filterStatus, setFilterStatus] = useState("");

    const [show, setShow] = useState(false);
    const [editing, setEditing] = useState(null);
    const [form, setForm] = useState({
        contractId: "",
        amount: "",
        paymentDate: todayStr(),
        method: "TRANSFER",
        status: "PAID",
        note: "",
    });

    /* Load contracts for select + quick lookup */
    useEffect(() => {
        (async () => {
            try {
                const { data } = await api.get("/api/contracts", {
                    params: { page: 0, size: 1000, sort: "id,desc" },
                });
                const list = Array.isArray(data) ? data : data?.content || [];
                const norm = list.map((c) => ({
                    id: c.id,
                    code: c.contractCode || c.code || `HD-${c.id}`,
                    title: c.title || "",
                    customerName: c.customerName || c.customer?.name || "",
                    totalAmount: Number(c.totalAmount || c.value || 0),
                }));
                setContracts(norm);
                const map = {};
                norm.forEach((x) => (map[x.id] = x));
                setByIdContract(map);
            } catch (e) {
                console.warn("load contracts failed", e);
                setContracts([]);
                setByIdContract({});
            }
        })();
    }, []);

    /* Load payments with filters/pagination */
    useEffect(() => {
        loadPayments();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [page, filterContractId, filterStatus]);

    async function loadPayments() {
        setLoading(true);
        try {
            const params = { page, size: PAGE_SIZE, sort: "id,desc" };
            // If backend supports query params:
            if (filterContractId) params.contractId = filterContractId;
            if (filterStatus) params.status = filterStatus;

            const { data } = await api.get("/api/payments", { params });
            const list = Array.isArray(data) ? data : data?.content || [];
            const pages = Array.isArray(data) ? 1 : (data?.totalPages || 1);

            const norm = list.map((p) => {
                const cid = p.contractId || p.contract?.id;
                const amt = Number(p.amount ?? p.money ?? 0);
                const st = p.status || p.paymentStatus;
                return {
                    id: p.id,
                    contractId: cid,
                    contractCode: p.contractCode || p.contract?.contractCode || "",
                    customerName:
                        p.customerName || p.contract?.customerName || p.contract?.customer?.name || "",
                    amount: amt,
                    paymentDate: p.paymentDate || p.date || p.createdAt?.slice?.(0, 10) || "",
                    method: p.method || p.paymentMethod || "",
                    status: String(st || "PAID").toUpperCase(),
                    note: p.note || p.description || "",
                };
            });

            setRows(norm);
            setTotalPages(pages);
        } catch (e) {
            console.error(e);
            setRows([]);
            setTotalPages(1);
        } finally {
            setLoading(false);
        }
    }

    /* Aggregation per selected contract */
    const agg = useMemo(() => {
        if (!filterContractId) return null;
        const cid = Number(filterContractId);
        const contract = byIdContract[cid];
        const paid = rows
            .filter((r) => r.contractId === cid && r.status === "PAID")
            .reduce((s, r) => s + (r.amount || 0), 0);
        const total = Number(contract?.totalAmount || 0);
        return {
            total,
            paid,
            remain: Math.max(0, total - paid),
            code: contract?.code,
            customerName: contract?.customerName,
            title: contract?.title,
        };
    }, [filterContractId, rows, byIdContract]);

    /* Modal open/close */
    function openCreate() {
        setEditing(null);
        setForm({
            contractId: filterContractId || (contracts[0]?.id || ""),
            amount: "",
            paymentDate: todayStr(),
            method: "TRANSFER",
            status: "PAID",
            note: "",
        });
        setShow(true);
    }
    function openEdit(row) {
        setEditing(row);
        setForm({
            contractId: row.contractId || "",
            amount: String(row.amount || ""),
            paymentDate: toISO(row.paymentDate) || todayStr(),
            method: row.method || "TRANSFER",
            status: row.status || "PAID",
            note: row.note || "",
        });
        setShow(true);
    }

    /* CRUD */
    async function save(e) {
        e.preventDefault();

        // basic validations
        const amt = parseMoney(form.amount);
        if (!form.contractId) return alert("Vui lòng chọn hợp đồng");
        if (amt <= 0) return alert("Số tiền thanh toán phải > 0");

        const payload = {
            contractId: Number(form.contractId),
            amount: amt,
            paymentDate: toISO(form.paymentDate) || todayStr(),
            method: form.method || null,
            note: form.note?.trim() || null,
            status: String(form.status || "PAID").toUpperCase(), // PAID | PENDING | CANCELLED
        };

        try {
            if (editing) {
                await api.put(`/api/payments/${editing.id}`, payload);
            } else {
                await api.post("/api/payments", payload);
            }
            setShow(false);
            await loadPayments();
        } catch (err) {
            console.error(err?.response || err);
            if (err?.response?.status === 401 || err?.response?.status === 403) {
                alert("Phiên đăng nhập hết hạn hoặc không đủ quyền. Vui lòng đăng nhập lại.");
                return (window.location.href = "/login");
            }
            const data = err?.response?.data;
            const msg =
                data?.message ||
                data?.error ||
                (typeof data === "string" ? data : "Lưu thanh toán thất bại");
            alert(msg);
        }
    }

    async function remove(row) {
        if (!window.confirm(`Xóa phiếu thu #${row.id}?`)) return;
        try {
            await api.delete(`/api/payments/${row.id}`);
            await loadPayments();
        } catch (err) {
            const data = err?.response?.data;
            alert(
                data?.message ||
                data?.error ||
                (typeof data === "string" ? data : "Xóa thanh toán thất bại")
            );
        }
    }

    /* UI helpers */
    const statusChipClass = (s) => {
        const x = String(s || "").toUpperCase();
        if (x === "PAID") return "bg-emerald-100 text-emerald-700";
        if (x === "PENDING") return "bg-amber-100 text-amber-700";
        if (x === "CANCELLED" || x === "CANCELED") return "bg-rose-100 text-rose-700";
        return "bg-slate-100 text-slate-700";
    };

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-lg font-semibold text-slate-900">Thanh toán</h2>
                    <p className="text-sm text-slate-500">Quản lý thu tiền theo hợp đồng</p>
                </div>
                {canEdit && (
                    <button
                        onClick={openCreate}
                        className="px-4 py-2 rounded-xl bg-indigo-600 text-white hover:bg-indigo-700 shadow"
                    >
                        Thêm phiếu thu
                    </button>
                )}
            </div>

            {/* Filters */}
            <div className="flex flex-col md:flex-row gap-3">
                <select
                    value={filterContractId}
                    onChange={(e) => {
                        setPage(0);
                        setFilterContractId(e.target.value);
                    }}
                    className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm"
                >
                    <option value="">— Tất cả hợp đồng —</option>
                    {contracts.map((c) => (
                        <option key={c.id} value={c.id}>
                            {c.code} — {c.customerName || c.title}
                        </option>
                    ))}
                </select>

                <select
                    value={filterStatus}
                    onChange={(e) => {
                        setPage(0);
                        setFilterStatus(e.target.value);
                    }}
                    className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm"
                >
                    <option value="">— Tất cả trạng thái —</option>
                    {statusMap.map((s) => (
                        <option key={s.value} value={s.value}>
                            {s.label}
                        </option>
                    ))}
                </select>
            </div>

            {/* Contract summary */}
            {agg && (
                <div className="rounded-2xl border border-indigo-100 bg-white p-4 shadow-sm">
                    <div className="text-sm text-slate-600 mb-2">
                        <span className="font-medium">{agg.code}</span> — {agg.customerName || agg.title || "-"}
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                        <div className="rounded-xl bg-slate-50 p-3">
                            <div className="text-xs text-slate-500">Giá trị HĐ</div>
                            <div className="font-semibold tabular-nums">{money(agg.total)}</div>
                        </div>
                        <div className="rounded-xl bg-emerald-50 p-3">
                            <div className="text-xs text-slate-500">Đã thu</div>
                            <div className="font-semibold tabular-nums">{money(agg.paid)}</div>
                        </div>
                        <div className="rounded-xl bg-amber-50 p-3">
                            <div className="text-xs text-slate-500">Còn lại</div>
                            <div
                                className={
                                    "font-semibold tabular-nums " + (agg.remain < 0 ? "text-rose-600" : "")
                                }
                            >
                                {money(agg.remain)}
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* List */}
            {loading ? (
                <div className="p-6 bg-white rounded-2xl border">Đang tải…</div>
            ) : rows.length === 0 ? (
                <div className="p-6 bg-white rounded-2xl border text-slate-500">Chưa có thanh toán</div>
            ) : (
                <div className="rounded-2xl border border-indigo-100 overflow-hidden bg-white">
                    <div className="overflow-x-auto">
                        <table className="min-w-full text-sm">
                            <thead className="bg-slate-50 text-slate-700">
                            <tr>
                                <th className="text-left px-4 py-3">Mã HĐ</th>
                                <th className="text-left px-4 py-3">Khách hàng</th>
                                <th className="text-left px-4 py-3">Ngày thu</th>
                                <th className="text-right px-4 py-3">Số tiền</th>
                                <th className="text-left px-4 py-3">Phương thức</th>
                                <th className="text-left px-4 py-3">Trạng thái</th>
                                <th className="text-left px-4 py-3">Ghi chú</th>
                                <th className="text-right px-4 py-3">Thao tác</th>
                            </tr>
                            </thead>
                            <tbody>
                            {rows.map((r) => {
                                const code = r.contractCode || byIdContract[r.contractId]?.code || `HD-${r.contractId}`;
                                const customer = r.customerName || byIdContract[r.contractId]?.customerName || "-";
                                return (
                                    <tr key={r.id} className="border-t">
                                        <td className="px-4 py-2">{code}</td>
                                        <td className="px-4 py-2">{customer}</td>
                                        <td className="px-4 py-2">{toISO(r.paymentDate)}</td>
                                        <td className="px-4 py-2 text-right font-medium tabular-nums">
                                            {money(r.amount)}
                                        </td>
                                        <td className="px-4 py-2">{methodMap.find(m => m.value === r.method)?.label || r.method || "-"}</td>
                                        <td className="px-4 py-2">
                        <span className={`px-2 py-0.5 rounded-full text-xs ${statusChipClass(r.status)}`}>
                          {statusLabel(r.status)}
                        </span>
                                        </td>
                                        <td className="px-4 py-2 max-w-[360px] truncate" title={r.note || ""}>
                                            {r.note || "—"}
                                        </td>
                                        <td className="px-4 py-2 text-right">
                                            {canEdit && (
                                                <button
                                                    onClick={() => openEdit(r)}
                                                    className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100 mr-2"
                                                >
                                                    Sửa
                                                </button>
                                            )}
                                            {canDelete && (
                                                <button
                                                    onClick={() => remove(r)}
                                                    className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100"
                                                >
                                                    Xóa
                                                </button>
                                            )}
                                        </td>
                                    </tr>
                                );
                            })}
                            </tbody>
                        </table>
                    </div>

                    {/* Pagination */}
                    <div className="flex items-center justify-between px-4 py-3 bg-slate-50">
                        <div className="text-sm">Trang {page + 1}/{totalPages}</div>
                        <div className="flex gap-2">
                            <button
                                className="px-3 py-1.5 rounded bg-white border disabled:opacity-50"
                                onClick={() => setPage((p) => Math.max(0, p - 1))}
                                disabled={page <= 0}
                            >
                                ← Trước
                            </button>
                            <button
                                className="px-3 py-1.5 rounded bg-white border disabled:opacity-50"
                                onClick={() => setPage((p) => p + 1)}
                                disabled={page + 1 >= totalPages}
                            >
                                Sau →
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Modal */}
            {show && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl rounded-2xl bg-white shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">{editing ? "Sửa phiếu thu" : "Thêm phiếu thu"}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={() => setShow(false)}>
                                Đóng
                            </button>
                        </div>

                        <form onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="text-sm text-slate-600">Hợp đồng</label>
                                <select
                                    required
                                    value={form.contractId}
                                    onChange={(e) => setForm((f) => ({ ...f, contractId: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm"
                                >
                                    <option value="">— Chọn hợp đồng —</option>
                                    {contracts.map((c) => (
                                        <option key={c.id} value={c.id}>
                                            {c.code} — {c.customerName || c.title}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Ngày thu</label>
                                <input
                                    type="date"
                                    required
                                    value={form.paymentDate}
                                    onChange={(e) => setForm((f) => ({ ...f, paymentDate: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Số tiền (₫)</label>
                                <input
                                    inputMode="numeric"
                                    required
                                    value={form.amount}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, amount: String(parseMoney(e.target.value)) }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm tabular-nums"
                                    placeholder="VD: 5.000.000"
                                />
                                <div className="text-xs text-slate-500 mt-1">
                                    = <span className="font-medium">{money(parseMoney(form.amount))}</span>
                                </div>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Phương thức</label>
                                <select
                                    value={form.method}
                                    onChange={(e) => setForm((f) => ({ ...f, method: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm"
                                >
                                    {methodMap.map((m) => (
                                        <option key={m.value} value={m.value}>
                                            {m.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Trạng thái</label>
                                <select
                                    value={form.status}
                                    onChange={(e) => setForm((f) => ({ ...f, status: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm"
                                >
                                    {statusMap.map((s) => (
                                        <option key={s.value} value={s.value}>
                                            {s.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Ghi chú</label>
                                <textarea
                                    rows={3}
                                    value={form.note}
                                    onChange={(e) => setForm((f) => ({ ...f, note: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow-sm"
                                    placeholder="VD: Đợt 1 theo tiến độ"
                                />
                            </div>

                            <div className="md:col-span-2 flex justify-end gap-2 pt-2">
                                <button
                                    type="button"
                                    className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                    onClick={() => setShow(false)}
                                >
                                    Hủy
                                </button>
                                <button className="px-4 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">
                                    Lưu
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
